from __future__ import annotations

import os
import json
import shutil
import subprocess
import sys
from pathlib import Path
from typing import Any


ROOT = Path(__file__).resolve().parents[1]
FRONTEND_APPS = [
    "apps/admin-dashboard",
    "apps/patient-portal",
    "apps/provider-portal",
    "apps/integration-console",
    "apps/public-website",
]
REQUIRED_DIRECTORIES = [
    "apps",
    "services",
    "packages",
    "scripts",
    "tests",
    "database",
    "database/migrations",
    "infrastructure/helm/healthbridge",
]
REQUIRED_FILES = [
    "package.json",
    "package-lock.json",
    "docker-compose.yml",
    "database/schema.sql",
    "infrastructure/helm/healthbridge/Chart.yaml",
    "infrastructure/helm/healthbridge/values.yaml",
    "packages/sdk-go/client.go",
    "packages/sdk-go/go.mod",
]
EXCLUDED_PARTS = {".git", ".venv", "__pycache__", "node_modules", "dist", "build"}


def run(command: list[str], cwd: Path = ROOT) -> None:
    print("+", " ".join(command), flush=True)
    subprocess.run(command, cwd=cwd, check=True)


def command_available(command: str) -> bool:
    return shutil.which(command) is not None


def command_succeeds(command: list[str], cwd: Path = ROOT) -> bool:
    return subprocess.run(
        command,
        cwd=cwd,
        stdout=subprocess.DEVNULL,
        stderr=subprocess.DEVNULL,
        check=False,
    ).returncode == 0


def skip(message: str) -> None:
    print(f"skipping {message}", flush=True)


def is_excluded(path: Path) -> bool:
    return any(part in EXCLUDED_PARTS for part in path.parts)


def is_helm_template(path: Path) -> bool:
    if "templates" not in path.parts:
        return False

    for parent in path.parents:
        if parent.name == "templates" and (parent.parent / "Chart.yaml").exists():
            return True
    return False


def load_yaml(path: Path) -> Any:
    import yaml

    with path.open(encoding="utf-8") as handle:
        return yaml.safe_load(handle)


def load_top_level_yaml_mapping(path: Path) -> dict[str, str]:
    data: dict[str, str] = {}
    for line in path.read_text(encoding="utf-8").splitlines():
        if line[:1].isspace():
            continue
        stripped = line.strip()
        if not stripped or stripped.startswith("#") or ":" not in stripped:
            continue
        key, value = stripped.split(":", 1)
        data[key.strip()] = value.strip().strip("\"'")
    return data


def load_compose_build_contexts(path: Path) -> list[str]:
    try:
        compose = load_yaml(path) or {}
    except ModuleNotFoundError as exc:
        if exc.name != "yaml":
            raise
        return [
            line.split(":", 1)[1].strip().strip("\"'")
            for line in path.read_text(encoding="utf-8").splitlines()
            if line.strip().startswith("build:")
        ]

    contexts: list[str] = []
    for service in (compose.get("services") or {}).values():
        if not isinstance(service, dict):
            continue
        build_context = service.get("build")
        if isinstance(build_context, str):
            contexts.append(build_context)
        elif isinstance(build_context, dict) and isinstance(build_context.get("context"), str):
            contexts.append(build_context["context"])
    return contexts


def verify_required_paths() -> None:
    for directory in REQUIRED_DIRECTORIES:
        path = ROOT / directory
        if not path.is_dir():
            raise FileNotFoundError(f"required directory is missing: {directory}")

    for file_name in REQUIRED_FILES:
        path = ROOT / file_name
        if not path.is_file():
            raise FileNotFoundError(f"required file is missing: {file_name}")

    print(
        f"verified {len(REQUIRED_DIRECTORIES)} required directories "
        f"and {len(REQUIRED_FILES)} required files",
        flush=True,
    )


def verify_frontend_workspace() -> None:
    package_json = json.loads((ROOT / "package.json").read_text(encoding="utf-8"))
    workspaces = package_json.get("workspaces")
    if sorted(workspaces or []) != sorted(FRONTEND_APPS):
        raise ValueError("root package.json workspaces do not match frontend apps")

    for app in FRONTEND_APPS:
        app_dir = ROOT / app
        for file_name in ("package.json", "package-lock.json", "vite.config.ts"):
            path = app_dir / file_name
            if not path.is_file():
                raise FileNotFoundError(f"required frontend file is missing: {path.relative_to(ROOT)}")

    print(f"verified root npm workspace metadata and {len(FRONTEND_APPS)} frontend lockfiles", flush=True)


def validate_json() -> None:
    count = 0
    for path in ROOT.rglob("*.json"):
        if is_excluded(path):
            continue
        with path.open(encoding="utf-8") as handle:
            json.load(handle)
        count += 1
    print(f"validated {count} json files", flush=True)


def validate_yaml() -> None:
    try:
        import yaml
    except Exception as exc:
        print(f"skipping yaml validation: {exc}", flush=True)
        return

    count = 0
    for pattern in ("*.yaml", "*.yml"):
        for path in ROOT.rglob(pattern):
            if is_excluded(path):
                continue
            if is_helm_template(path):
                continue
            with path.open(encoding="utf-8") as handle:
                yaml.safe_load(handle)
            count += 1
    print(f"validated {count} non-template yaml files", flush=True)


def run_services() -> None:
    for app in sorted((ROOT / "services").glob("*/app.py")):
        run([sys.executable, str(app)])


def run_frontends() -> None:
    if not command_available("npm"):
        raise RuntimeError("npm is required for frontend workspace verification")

    run(["npm", "test"])
    run(["npm", "run", "build"])


def verify_go_sdk() -> None:
    sdk_dir = ROOT / "packages/sdk-go"
    if not command_available("go"):
        skip("Go SDK tests: go not found")
        return

    run(["go", "test", "./..."], cwd=sdk_dir)


def verify_helm_chart() -> None:
    chart_dir = ROOT / "infrastructure/helm/healthbridge"
    try:
        chart = load_yaml(chart_dir / "Chart.yaml")
    except ModuleNotFoundError as exc:
        if exc.name != "yaml":
            raise
        chart = load_top_level_yaml_mapping(chart_dir / "Chart.yaml")
    except Exception as exc:
        raise RuntimeError(f"failed to load Helm chart metadata: {exc}") from exc

    for field in ("apiVersion", "name", "version", "type"):
        if not chart or not chart.get(field):
            raise ValueError(f"Helm Chart.yaml is missing required field: {field}")
    print("verified Helm chart metadata", flush=True)

    if not command_available("helm"):
        skip("Helm lint: helm not found")
        return

    run(["helm", "lint", str(chart_dir)])


def verify_database_schema() -> None:
    schema = ROOT / "database/schema.sql"
    migrations_dir = ROOT / "database/migrations"
    migrations = sorted(migrations_dir.glob("*.sql"))
    if not migrations:
        raise FileNotFoundError("database/migrations must contain at least one SQL migration")

    schema_text = schema.read_text(encoding="utf-8")
    for table_name in ("patients", "integration_events", "audit_events"):
        if f"CREATE TABLE {table_name}" not in schema_text:
            raise ValueError(f"database/schema.sql is missing table: {table_name}")

    print(f"verified database schema and {len(migrations)} migrations are available", flush=True)

    if not command_available("psql"):
        skip("database schema execution: psql not found")
        return

    database_url = os.environ.get("HEALTHBRIDGE_DATABASE_URL") or os.environ.get("DATABASE_URL")
    if not database_url:
        skip("database schema execution: psql found but HEALTHBRIDGE_DATABASE_URL/DATABASE_URL is not set")
        return

    run(
        [
            "psql",
            "--dbname",
            database_url,
            "-v",
            "ON_ERROR_STOP=1",
            "-c",
            "BEGIN; SET LOCAL search_path TO pg_temp;",
            "-f",
            str(schema),
            "-c",
            "ROLLBACK;",
        ]
    )


def verify_docker_inputs() -> None:
    service_dockerfiles = sorted((ROOT / "services").glob("*/Dockerfile"))
    if not service_dockerfiles:
        raise FileNotFoundError("services must contain Dockerfiles")

    for dockerfile in service_dockerfiles:
        text = dockerfile.read_text(encoding="utf-8")
        if "FROM " not in text:
            raise ValueError(f"{dockerfile.relative_to(ROOT)} is missing a FROM instruction")
        if not (dockerfile.parent / "app.py").is_file():
            raise FileNotFoundError(f"{dockerfile.parent.relative_to(ROOT)} is missing app.py")

    try:
        compose_build_contexts = load_compose_build_contexts(ROOT / "docker-compose.yml")
    except Exception as exc:
        raise RuntimeError(f"failed to load docker-compose.yml: {exc}") from exc

    for build_context in compose_build_contexts:
        context_path = (ROOT / build_context).resolve()
        if not context_path.is_dir():
            raise FileNotFoundError(f"docker compose build context is missing: {build_context}")
        if not (context_path / "Dockerfile").is_file():
            raise FileNotFoundError(f"docker compose build context has no Dockerfile: {build_context}")

    print(f"verified {len(service_dockerfiles)} service Dockerfiles and docker-compose build contexts", flush=True)

    if not command_available("docker"):
        skip("Docker compose validation: docker not found")
        return

    if not command_succeeds(["docker", "compose", "version"]):
        skip("Docker compose validation: docker compose is not available")
        return

    run(["docker", "compose", "-f", str(ROOT / "docker-compose.yml"), "config", "--quiet"])


def main() -> None:
    verify_required_paths()
    verify_frontend_workspace()
    run([sys.executable, "-m", "compileall", "-q", "services", "packages", "scripts"])
    run([sys.executable, "-m", "pytest", "-q"])
    validate_json()
    validate_yaml()
